+    /// Write data to the stream using async I/O.
+    async fn write_all(&mut self, data: &[u8]) -> Result<(), PgError> {
+        let mut pos = 0;
+        while pos < data.len() {
+            let written = std::future::poll_fn(|cx| {
+                Pin::new(&mut self.inner.stream).poll_write(cx, &data[pos..])
