+        assert!(bool::from_sql(b"true", oid::BOOL, Format::Text).unwrap());
+        assert!(!bool::from_sql(b"f", oid::BOOL, Format::Text).unwrap());
+        assert!(!bool::from_sql(b"false", oid::BOOL, Format::Text).unwrap());
